// Some portions generated by Claude
package org.eclipse.rdf4j.sail.shacl;

import static org.junit.jupiter.api.Assertions.assertThrows;

import java.io.StringReader;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.Value;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.model.vocabulary.RDF;
import org.eclipse.rdf4j.model.vocabulary.RDF4J;
import org.eclipse.rdf4j.repository.RepositoryException;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.repository.sail.SailRepositoryConnection;
import org.eclipse.rdf4j.rio.RDFFormat;
import org.eclipse.rdf4j.sail.memory.MemoryStore;
import org.junit.jupiter.api.Test;

/**
 * Transactional validation fetches the pre-transaction state for affected targets through bulked queries whose parsed
 * 'VALUES (?a) {}' placeholders get the transaction's bindings injected by matching on the node's binding names.
 * BindingSetAssignment derives binding names from the actual rows, so a zero-row placeholder reports no names — the
 * injection sites must match on the DECLARED header names or injection is silently skipped and validation under-reports
 * violations across transactions.
 */
public class BulkValuesInjectionTest {

	private static final String EX = "http://example.com/ns#";

	private final ValueFactory vf = SimpleValueFactory.getInstance();
	private final IRI person1 = vf.createIRI(EX, "person1");
	private final IRI person2 = vf.createIRI(EX, "person2");
	private final IRI personClass = vf.createIRI(EX, "Person");
	private final IRI ssn = vf.createIRI(EX, "ssn");
	private final Value value1 = vf.createLiteral("a");
	private final Value value2 = vf.createLiteral("b");

	private String shapes(String constraint) {
		return String.join("\n", "",
				"@prefix ex: <http://example.com/ns#> .",
				"@prefix sh: <http://www.w3.org/ns/shacl#> .",
				"",
				"ex:PersonShape",
				"	a sh:NodeShape  ;",
				"	sh:targetClass ex:Person ;",
				"	sh:property [",
				"		sh:path ex:ssn ;",
				constraint,
				"	] .",
				"");
	}

	/**
	 * The second transaction only adds one ssn value; the violation exists only when validation joins it with the value
	 * committed in the first transaction — the bulked fetch of pre-transaction state.
	 */
	@Test
	public void maxCountViolationSpanningTransactionsIsDetected() throws Throwable {
		SailRepository sailRepository = new SailRepository(new ShaclSail(new MemoryStore()));

		try (SailRepositoryConnection connection = sailRepository.getConnection()) {
			connection.begin();
			connection.add(new StringReader(shapes("sh:maxCount 1 ;")), "", RDFFormat.TRIG, RDF4J.SHACL_SHAPE_GRAPH);
			connection.add(person1, RDF.TYPE, personClass);
			connection.add(person1, ssn, value1);
			connection.commit();

			connection.begin();
			connection.add(person1, ssn, value2);
			assertThrows(ShaclSailValidationException.class, () -> {
				try {
					connection.commit();
				} catch (RepositoryException e) {
					throw e.getCause();
				}
			});
		} finally {
			sailRepository.shutDown();
		}
	}

	/** A new target added in the second transaction must be validated against the shape from the first. */
	@Test
	public void minCountViolationForNewTargetIsDetected() throws Throwable {
		SailRepository sailRepository = new SailRepository(new ShaclSail(new MemoryStore()));

		try (SailRepositoryConnection connection = sailRepository.getConnection()) {
			connection.begin();
			connection.add(new StringReader(shapes("sh:minCount 1 ;")), "", RDFFormat.TRIG, RDF4J.SHACL_SHAPE_GRAPH);
			connection.add(person1, RDF.TYPE, personClass);
			connection.add(person1, ssn, value1);
			connection.commit();

			connection.begin();
			connection.add(person2, RDF.TYPE, personClass);
			assertThrows(ShaclSailValidationException.class, () -> {
				try {
					connection.commit();
				} catch (RepositoryException e) {
					throw e.getCause();
				}
			});
		} finally {
			sailRepository.shutDown();
		}
	}
}
